function fmtK(n) { return n >= 1000 ? `$${(n / 1000).toFixed(1)}K` : `$${n.toLocaleString()}`; }
function fmtDollar(n) { return `$${n.toLocaleString()}`; }

function getRegionMultiplier(region) {
  return pricingModel.laborMultiplierByRegion?.[region] || 1.0;
}

